const EV_DESTINATIONS = [{ne:'कागुने',en:'Kagune'},{ne:'टिमुरे',en:'Timure'},{ne:'देवीघाट',en:'Devighat'},{ne:'भोर्ले',en:'Bhorle'},{ne:'स्याफ्रु',en:'Syafru'},{ne:'काउले / चोकदे',en:'Kaule / Chokde'},{ne:'धुन्चे',en:'Dhunche'},{ne:'गोर्स्याङ',en:'Gorsyang'},{ne:'शान्तिबजार',en:'Shantibazar'},{ne:'कालिकास्थान',en:'Kalikasthan'},{ne:'बाघखोर',en:'Baghkhor'},{ne:'साउगाउँ',en:'Saugaun'},{ne:'त्रिशूली',en:'Trishuli'},{ne:'नारायणघाट',en:'Narayanghat'}];

