      <div className="search-wrap">
        <div className="container">
          <div className="search-box">
            <h3>{t('आफ्नो बस र EV माइक्रो खोज्नुहोस्','Search Your Bus and EV')}</h3>
            <div className="search-type-tabs">
              <button className={`search-type-tab${searchType==='bus'?' active':''}`} data-stype="bus" onClick={() => { setSearchType('bus'); setSearchFrom(''); setSearchTo(''); }}>🚌 <span>{t('डिलक्स बस','Deluxe Bus')}</span></button>
              <button className={`search-type-tab${searchType==='ev'?' active':''}`} data-stype="ev" onClick={() => { setSearchType('ev'); setSearchFrom(''); setSearchTo(''); }}>⚡ <span>{t('EV माइक्रो','EV Micro')}</span></button>
            </div>
            <div className="search-fields">
              <div className="field">
                <label>{t('कहाँबाट','From')}</label>
                <select value={searchFrom} onChange={e => setSearchFrom(e.target.value)}>
                  <option value="">-- Select --</option>
                  {fromList.map(d => <option key={d.en} value={lang==='ne'?d.ne:d.en}>{lang==='ne'?d.ne:d.en}</option>)}
                </select>
              </div>
              <div className="field">
                <label>{t('कहाँसम्म','To')}</label>
                <select value={searchTo} onChange={e => setSearchTo(e.target.value)}>
                  <option value="">-- Select --</option>
                  {destList.map(d => <option key={d.en} value={lang==='ne'?d.ne:d.en}>{lang==='ne'?d.ne:d.en}</option>)}
                </select>
              </div>
              <div className="field">
                <label>{t('यात्रा मिति','Travel Date')}</label>
                <input type="date" value={searchDate} min={new Date().toISOString().split('T')[0]} onChange={e => setSearchDate(e.target.value)} />
              </div>
              <div className="field">
                <label>{t('यात्री संख्या','Passengers')}</label>
                <select value={searchPassengers} onChange={e => setSearchPassengers(e.target.value)}>
                  <option value="1">{t('१ यात्री','1 Passenger')}</option>
                  <option value="2">{t('२ यात्री','2 Passengers')}</option>
                  <option value="3">{t('३ यात्री','3 Passengers')}</option>
                  <option value="4">{t('४+ यात्री','4+ Passengers')}</option>
                </select>
              </div>
              <div className="field">
                <label>&nbsp;</label>
                <div className="search-btn-group">
                  <button className="btn-search" onClick={doSearch}>{t('बस खोज्नुहोस्','Search Buses')}</button>
                  <button className={`btn-reset${searchResults?' visible':''}`} onClick={doReset}>↺ {t('रिसेट','Reset')}</button>
                </div>
              </div>
            </div>

            {searchResults !== null && (
              <div className="search-results visible">
                <div className="results-header">
                  <div className="results-title">{t('उपलब्ध बसहरू','Available Buses')}</div>
                  <div className="results-meta">{searchMeta}</div>
                </div>
                {searchResults.length === 0 ? (
                  <div className="no-results"><span>🔍</span>{t('यस मार्गमा कुनै बस फेला परेन। कृपया अर्को मार्ग प्रयास गर्नुहोस्।','No buses found for this route. Please try a different route.')}</div>
                ) : searchResults.map((r,i) => {
                  const passengers = parseInt(searchPassengers) || 1;
                  const totalFare = r.fare * passengers;
                  const fromLabel = lang==='ne'?r.fromNe:r.fromEn;
                  const toLabel = lang==='ne'?r.toNe:r.toEn;
                  const typeLabel = lang==='ne'?r.typeNe:r.typeEn;
                  const typeColor = r.type==='ev'?'#166534':'#92400e';
                  const typeBg = r.type==='ev'?'#dcfce7':'#fef3c7';
                  return (
                    <div className="result-card" key={i}>
                      <div className="result-type">
                        <div className="result-type-icon">{r.type==='ev'?'⚡':'🚌'}</div>
                        <div className="result-type-badge" style={{background:typeBg,color:typeColor}}>{typeLabel}</div>
                      </div>
                      <div className="result-route">
                        <div className="result-route-row"><span>{fromLabel}</span><span className="result-route-arrow">→</span><span>{toLabel}</span></div>
                        <div className="result-stops">📍 {t('हुँदै','Via')}: {r.via}</div>
                      </div>
                      <div className="result-time"><div className="result-depart">{r.time}</div><div className="result-depart-label">{t('प्रस्थान','Departure')}</div></div>
                      <div className="result-fare-wrap">
                        <div className="result-fare">Rs. {totalFare.toLocaleString()}</div>
                        <div className="result-fare-label">{t('कुल भाडा','Total Fare')}</div>
                        {passengers>1 && <div className="result-passengers">({passengers} pax × Rs.{r.fare})</div>}
                      </div>
                      <a href="#contact" className="result-book">{t('टिकट बुक','Book Now')}</a>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      </div>

